import{_ as l,c as e,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/Perplexica-AI工具.md","filePath":"github汇总/AI工具/Perplexica-AI工具.md"}'),h={name:"github汇总/AI工具/Perplexica-AI工具.md"};function o(c,a,t,d,n,s){return i(),e("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>Perplexica</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>ItzCrazyKns</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><ul><li>传统搜索引擎只返回链接，不理解用户意图</li><li>Perplexity AI等工具需要付费</li><li>缺少开源的AI搜索引擎方案</li><li>难以在本地部署AI驱动的搜索</li></ul><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>开源的AI驱动搜索引擎，受Perplexity AI启发</li><li>理解用户问题意图，提供智能回答</li><li>支持Docker部署和本地安装</li><li>支持连接Ollama实现本地模型运行</li><li>可配置SearXNG作为搜索源</li><li>使用TypeScript开发</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>开源免费，零付费使用</li><li>GitHub星标已超两万五千</li><li>支持本地模型运行，保护隐私</li><li>理解用户意图，提供智能回答</li><li>部署简单，支持Docker</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明，但GitHub星标已超两万五千</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/ItzCrazyKns/Perplexica" target="_blank" rel="noreferrer">https://github.com/ItzCrazyKns/Perplexica</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>本教程适用于想要使用Perplexica搭建AI搜索引擎的用户，支持Windows、Linux和MacOS系统。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><h3 id="_1-node-js版本检查" tabindex="-1">1. Node.js版本检查 <a class="header-anchor" href="#_1-node-js版本检查" aria-label="Permalink to “1. Node.js版本检查”">​</a></h3><ul><li>步骤目标：确认Node.js版本满足要求</li><li>执行位置：本机终端</li><li>完整命令：<code>node --version</code></li><li>成功标志：显示Node.js 18.0或更高版本</li><li>失败处理：请安装或升级Node.js至18.0+版本</li></ul><h3 id="_2-docker检查-可选" tabindex="-1">2. Docker检查（可选） <a class="header-anchor" href="#_2-docker检查-可选" aria-label="Permalink to “2. Docker检查（可选）”">​</a></h3><ul><li>步骤目标：确认Docker已安装（使用Docker部署时）</li><li>执行位置：本机终端</li><li>完整命令：<code>docker --version</code></li><li>成功标志：显示Docker版本信息</li><li>失败处理：请安装Docker</li></ul><h3 id="_3-网络访问检查" tabindex="-1">3. 网络访问检查 <a class="header-anchor" href="#_3-网络访问检查" aria-label="Permalink to “3. 网络访问检查”">​</a></h3><ul><li>步骤目标：确认可以访问GitHub</li><li>执行位置：本机浏览器</li><li>检查方法：访问<a href="https://github.com/ItzCrazyKns/Perplexica" target="_blank" rel="noreferrer">https://github.com/ItzCrazyKns/Perplexica</a></li><li>成功标志：可以正常访问项目页面</li><li>失败处理：请配置海外网络环境 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><h2 id="主路径-docker部署-推荐" tabindex="-1">主路径：Docker部署（推荐） <a class="header-anchor" href="#主路径-docker部署-推荐" aria-label="Permalink to “主路径：Docker部署（推荐）”">​</a></h2><h3 id="步骤1-克隆项目仓库" tabindex="-1">步骤1：克隆项目仓库 <a class="header-anchor" href="#步骤1-克隆项目仓库" aria-label="Permalink to “步骤1：克隆项目仓库”">​</a></h3><ul><li>步骤目标：从GitHub克隆Perplexica项目</li><li>执行位置：本机终端</li><li>完整命令：<code>git clone https://github.com/ItzCrazyKns/Perplexica.git</code></li><li>成功标志：项目克隆完成</li><li>失败处理：检查网络连接</li></ul><h3 id="步骤2-进入项目目录" tabindex="-1">步骤2：进入项目目录 <a class="header-anchor" href="#步骤2-进入项目目录" aria-label="Permalink to “步骤2：进入项目目录”">​</a></h3><ul><li>步骤目标：进入Perplexica项目目录</li><li>执行位置：本机终端</li><li>完整命令：<code>cd Perplexica</code></li><li>成功标志：当前目录变为Perplexica</li><li>失败处理：确保克隆成功</li></ul><h3 id="步骤3-使用docker-compose启动" tabindex="-1">步骤3：使用Docker Compose启动 <a class="header-anchor" href="#步骤3-使用docker-compose启动" aria-label="Permalink to “步骤3：使用Docker Compose启动”">​</a></h3><ul><li>步骤目标：启动Perplexica服务</li><li>执行位置：项目目录终端</li><li>完整命令：<code>docker-compose up -d</code></li><li>成功标志：Docker容器启动成功</li><li>失败处理：检查Docker是否正常运行</li></ul><h3 id="步骤4-访问界面" tabindex="-1">步骤4：访问界面 <a class="header-anchor" href="#步骤4-访问界面" aria-label="Permalink to “步骤4：访问界面”">​</a></h3><ul><li>步骤目标：打开浏览器访问Perplexica</li><li>执行位置：本机浏览器</li><li>访问地址：<a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></li><li>成功标志：看到Perplexica界面</li><li>失败处理：检查容器是否正常运行</li></ul><h2 id="备选路径-本地安装" tabindex="-1">备选路径：本地安装 <a class="header-anchor" href="#备选路径-本地安装" aria-label="Permalink to “备选路径：本地安装”">​</a></h2><h3 id="步骤1-克隆项目并安装依赖" tabindex="-1">步骤1：克隆项目并安装依赖 <a class="header-anchor" href="#步骤1-克隆项目并安装依赖" aria-label="Permalink to “步骤1：克隆项目并安装依赖”">​</a></h3><ul><li>步骤目标：安装项目依赖</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npm install</code></li><li>成功标志：依赖安装完成</li><li>失败处理：检查网络连接</li></ul><h3 id="步骤2-构建项目" tabindex="-1">步骤2：构建项目 <a class="header-anchor" href="#步骤2-构建项目" aria-label="Permalink to “步骤2：构建项目”">​</a></h3><ul><li>步骤目标：构建Perplexica</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npm run build</code></li><li>成功标志：构建完成</li><li>失败处理：查看错误信息</li></ul><h3 id="步骤3-启动项目" tabindex="-1">步骤3：启动项目 <a class="header-anchor" href="#步骤3-启动项目" aria-label="Permalink to “步骤3：启动项目”">​</a></h3><ul><li>步骤目标：启动Perplexica</li><li>执行位置：项目目录终端</li><li>完整命令：<code>npm run start</code></li><li>成功标志：项目启动成功</li><li>失败处理：查看错误信息</li></ul><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><h3 id="_1-访问界面" tabindex="-1">1. 访问界面 <a class="header-anchor" href="#_1-访问界面" aria-label="Permalink to “1. 访问界面”">​</a></h3><ul><li>访问方式：浏览器</li><li>访问地址：<a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></li><li>预期返回：看到Perplexica界面</li></ul><h3 id="_2-配置searxng" tabindex="-1">2. 配置SearXNG <a class="header-anchor" href="#_2-配置searxng" aria-label="Permalink to “2. 配置SearXNG”">​</a></h3><ul><li>测试方法：在设置中填写SearXNG地址</li><li>预期返回：可以正常配置</li></ul><h3 id="_3-测试搜索" tabindex="-1">3. 测试搜索 <a class="header-anchor" href="#_3-测试搜索" aria-label="Permalink to “3. 测试搜索”">​</a></h3><ul><li>测试方法：尝试搜索一个问题</li><li>预期返回：可以正常搜索并获得回答</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><h3 id="现象1-node-js版本过低" tabindex="-1">现象1：Node.js版本过低 <a class="header-anchor" href="#现象1-node-js版本过低" aria-label="Permalink to “现象1：Node.js版本过低”">​</a></h3><ul><li>可能原因：Node.js版本不满足最低要求</li><li>解决步骤： <ol><li>检查当前Node.js版本：node --version</li><li>下载并安装Node.js 18.0或更高版本</li><li>重新打开终端并验证版本</li></ol></li></ul><h3 id="现象2-docker启动失败" tabindex="-1">现象2：Docker启动失败 <a class="header-anchor" href="#现象2-docker启动失败" aria-label="Permalink to “现象2：Docker启动失败”">​</a></h3><ul><li>可能原因：Docker未运行或配置问题</li><li>解决步骤： <ol><li>确认Docker已启动</li><li>检查端口3000是否被占用</li><li>查看Docker日志了解错误原因</li></ol></li></ul><h3 id="现象3-搜索无法使用" tabindex="-1">现象3：搜索无法使用 <a class="header-anchor" href="#现象3-搜索无法使用" aria-label="Permalink to “现象3：搜索无法使用”">​</a></h3><ul><li>可能原因：未配置SearXNG或配置错误</li><li>解决步骤： <ol><li>确认已正确配置SearXNG地址</li><li>检查SearXNG服务是否正常运行</li><li>查看浏览器控制台错误信息</li></ol></li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>基于公开可验证信息整理，完整教程请参考项目GitHub仓库的README文档。</p><p>更多详细文档请参考：</p><ul><li>GitHub仓库：<a href="https://github.com/ItzCrazyKns/Perplexica" target="_blank" rel="noreferrer">https://github.com/ItzCrazyKns/Perplexica</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',60)]))}const k=l(h,[["render",o]]);export{p as __pageData,k as default};
